th>Kamera</th>\r\n									<td>Çift Kamera</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Max Ekran Çözünürlüğü</th>\r\n									<td>1920 x 1080</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Mobil Bağlantı</th>\r\n									<td>Yok</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Pil Gücü (mAh)</th>\r\n									<td>7040 mAh</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Ram Kapasitesi</th>\r\n									<td>3 GB</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Sim Kart Uyumu</th>\r\n									<td>Hayır</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Temel İşlemci Hızı</th>\r\n									<td>2,4 GHz</td>\r\n								</tr>\r\n								<tr>\r\n									<th>USB Tipi</th>\r\n									<td>USB 2.0</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Wi-Fi</th>\r\n									<td>802.11 a/b/g/n/ac</td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n\r\n						<table>\r\n							<caption>Diğer</caption>\r\n							<tbody>\r\n								<tr>\r\n									<th>Garanti Süresi (Ay)</th>\r\n									<td>24</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Yurt Dışı Satış</th>\r\n									<td>Yok</td>\r\n								</tr>\r\n								<tr>\r\n									<th>Stok Kodu</th>\r\n									<td>HBCV000018PTDH</td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n', 'Samsung', 48787);
