(49, 'Lenovo Tab M10 TB328FU ZAAE0012TR 64 GB 4 GB RAM 10.1&quot; Tablet', 'd8a97c9d784432f72b4b0dd5bc5a198bc10fddcd.jpg', 'lenovo-tab-m10-tb328fu-zaae0012tr-64-gb-4-gb-ram-10.1&quot;-tablet', 3000, '<p><strong>Lenovo Tab M10 TB328FU ZAAE0012TR 64 GB 4 GB RAM 10.1&quot; Tablet &nbsp;</strong></p>\r\n\r\n<p><strong>Model:</strong>&nbsp;ZAAE0012TR&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n\r\n<p><strong>Ürün:</strong>&nbsp;TB328FU</p>\r\n\r\n<p><strong>EAN / UPC / JAN 196378578552</strong></p>\r\n\r\n<p><strong>Performans&nbsp;</strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n\r\n<p><strong>İşlemci:</strong>&nbsp;Unisoc T610 (8C, 2x A75 @1.8GHz + 6x A55 @1.8GHz)</p>\r\n\r\n<p><strong>Grafik Kartı:</strong>&nbsp;Entegre ARM Mali G52 3EE 2-Core</p>\r\n\r\n<p><strong>Chipset:</strong>&nbsp;Unisoc SoC Platform</p>\r\n\r\n<p><strong>RAM (Bellek):</strong>&nbsp;4GB Entegre LPDDR4x</p>\r\n\r\n<p><strong>Depolama:</strong>&nbsp;64GB (eMCP, eMMC 5.1)</p>\r\n\r\n<p><strong>Yükseltilebilir Hafıza:</strong>&nbsp;MicroSD Card (128GB&#39;a kadar, FAT32; 2TB, exFAT)</p>\r\n\r\n<p><strong>Kart Okuyucu:</strong>&nbsp;MicroSD Card Yuvası</p>\r\n\r\n<p><strong>Kamera:</strong>&nbsp;Ön 5.0MP / Arka 8.0MP</p>\r\n\r\n<p><strong>Mikrofon:</strong>&nbsp;Mono</p>\r\n\r\n<p><strong>Ses:</strong>&nbsp;Dolby Atmos ile optimize edilmiş çift hoparlör</p>\r\n\r\n<p><strong>Sensörler</strong></p>\r\n\r\n<p>Accelerometer (G) sensor</p>\r\n\r\n<p>Ambient light sensor (ALS)</p>\r\n\r\n<p>Hall sensor</p>\r\n\r\n<p>Proximity (P) sensor</p>\r\n\r\n<p><strong>Batarya:</strong>&nbsp;Entegre 5000mAh (Min.) / 5100mAh (Typ.)</p>\r\n\r\n<p><strong>Maksimum Batarya Süresi&nbsp; &nbsp; &nbsp;</strong>&nbsp;&nbsp; &nbsp;</p>\r\n\r\n<p><strong>Bekleme Süresi:</strong>&nbsp;4 hafta</p>\r\n\r\n<p><strong>Video Oynatma Süresi:</strong>&nbsp;10 saat</p>\r\n\r\n<p><strong>Tarayıcı Süresi:</strong>&nbsp;9 saat</p>\r\n\r\n<p><strong>Müzik oynatma süresi:</strong>&nbsp;64 saat</p>\r\n\r\n<p><strong>Şarj Süresi:</strong>&nbsp;3.5 saat&#3