(77, 'Sony Playstation 5 Digital Sürüm Oyun Konsolu', '832b7ff1a09ac14685fbf6eb733e0abc699d3957.jpg', 'sony-playstation-5-digital-surum-oyun-konsolu', 16440, '<p><strong>Sony Playstation 5 Digital Sürüm Oyun Konsolu</strong></p>\r\n\r\n<p><strong>Dahili hafıza</strong></p>\r\n\r\n<p>825 GB SSD</p>\r\n\r\n<p><strong>Dahili hafıza tipi</strong></p>\r\n\r\n<p>SSD</p>\r\n\r\n<p><strong>İşlemci Markası</strong></p>\r\n\r\n<p>AMD</p>\r\n\r\n<p><strong>İşlemci Teknolojisi</strong></p>\r\n\r\n<p>AMD Zen 2</p>\r\n\r\n<p><strong>İşlemci Hızı</strong></p>\r\n\r\n<p>3.5GHZ</p>\r\n\r\n<p><strong>İşlemci Çekirdek Sayısı</strong></p>\r\n\r\n<p>8</p>\r\n\r\n<p><strong>Grafik işlemci</strong></p>\r\n\r\n<p>AMD RDNA 2</p>\r\n\r\n<p><strong>Grafik işlemci frekansı</strong></p>\r\n\r\n<p>120HZ</p>\r\n\r\n<p><strong>Video Çözünürlüğü</strong></p>\r\n\r\n<p>4K</p>\r\n\r\n<p><strong>Depolama ortamı</strong></p>\r\n\r\n<p>SSD</p>\r\n\r\n<p><strong>Dahili hafıza</strong></p>\r\n\r\n<p>825GB SSD</p>\r\n\r\n<p><strong>Ethernet LAN bağlantısı</strong></p>\r\n\r\n<p>Var</p>\r\n\r\n<p><strong>Wi-Fi</strong></p>\r\n\r\n<p>Var</p>\r\n\r\n<p><strong>Bluetooth</strong></p>\r\n\r\n<p>Var</p>\r\n\r\n<p><strong>HDMI port sayısı</strong></p>\r\n\r\n<p>1</p>\r\n\r\n<p><strong>HDMI versiyonu</strong></p>\r\n\r\n<p>HDM! 2.1</p>\r\n\r\n<p><strong>USB 3.2 Gen 1 (3.1 Gen 1) Tip-A port sayısı</strong></p>\r\n\r\n<p>1</p>\r\n\r\n<p><strong>Fiş içi DC</strong></p>\r\n\r\n<p>Avrupa</p>\r\n\r\n<p><strong>HD türü</strong></p>\r\n\r\n<p>4K</p>\r\n\r\n<p><strong>Ram (Sistem Belleği)</strong></p>\r\n\r\n<p>16 GB</p>\r\n\r\n<p><strong>Ram Tipi</strong></p>\r\n\r\n<p>GDDR6</p>\r\n\r\n<p><strong>Disk Kapasitesi</strong></p>\r\n\r\n<p>825GB SSD</p>\r\n\r\n<p><strong>Paket İçeriği</strong></p>\r\n\r\n<p>PS5 Dijital versiyon konsol + Dualsense oyuncu kolu+ Güç &nbsp;&nbsp;Kablosu</p>\r\n\r\n<p><strong>Garanti</strong></p>\r\n\r\n<p>Eurasia garantili (24 Ay)</p>\r\n\r\n<p>*İnternetten oyun indirerek oynanabiliyor. Online oyunlarda internete bağlı olması gereklidir.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Üretim Yeri: Japonya</p>\r\n', 'Sony', 26019285),
(78, 'Microsoft XBox S Series Oyun Konsolu 512 GB Beyaz', '846cbcdeebe2e5884d009fa415d19560de462b59.jpg', 'microsoft-xbox-s-series-oyun-konsolu-512-gb-beyaz', 7101, '<p><strong>İŞLEMCİ</strong></p>\r\n\r\n<p>CPU. 3,6 GHz Hızında 8X Çekirdek (SMT ile 3,4 GHz) Özel Zen 2 CPU<br />\r\n<br />\r\nGPU. 4 TFLOP, 1,565 GHz Hızında 20 CU Özel RDNA 2 GPU<br />\r\n<br />\r\nSOC Yonga Boyutu. 197,05 mm2</p>\r\n\r\n<p><strong>BELLEK VE DEPOLAMA</strong></p>\r\n\r\n<p><strong>Bellek</strong>&nbsp;10 GB GDDR6 128 bit genişliğinde veri yolu<br />\r\n<br />\r\n<strong>Bellek Bant Genişliği</strong>&nbsp;224 GB/sn hızında 8GB, 56 GB/sn hızında 2GB.<br />\r\n<br />\r\n<strong>Dahili Depolama</strong>&nbsp;512 GB Özel NVME SSD<br />\r\n<br />\r\n<strong>G/Ç Aktarım Hızı</strong>&nbsp;2,4 GB/sn (Ham), 4,8 GB/sn (Sıkıştırılmış, özel donanım sıkıştırma açma bloğuyla)<br />\r\n<br />\r\n<strong>Genişletilebilir Depolama</strong>&nbsp;Xbox Series X|S için 1 TB Genişletme Kartı desteği, dahili depolama alanıyla tamamen eşleşir (ayrı olarak satılır). USB 3.1 harici HDD desteği (ayrı olarak satılır).</p>\r\n\r\n<p><strong>VİDEO ÖZELLİKLERİ</strong></p>\r\n\r\n<p><strong>Oyun Çözünürlüğü</strong>&nbsp;1440p<br />\r\n<br />\r\n<strong>Performans Hedefi&nbsp;</strong>120 FPS&#39;ye Kadar<br />\r\n<br />\r\n<strong>HDMI Özellikleri</strong>&nbsp;Otomatik Düşük Gecikme Modu, HDMI Değişken Yenileme Hızı, AMD FreeSync.<br />\r\n<br />\r\n<strong>SES ÖZELLİKLERİ</strong></p>\r\n\r\n<p>L-PCM, 7.1&#39;e kadar<br />\r\n<br />\r\nDolby Digital 5.1<br />\r\n<br />\r\nDTS 5.1<br />\r\n<br />\r\nAtmos ile Dolby TrueHD<br />\r\n<br />\r\n<strong>BAĞLANTI NOKTALARI VE BAĞLANTI</strong></p>\r\n\r\n<p><strong>HDMI</strong>&nbsp;1 adet HDMI 2.1 bağlantı noktası<br />\r\n<br />\r\n<strong>USB</strong>&nbsp;3 adet USB 3.1 Gen 1 bağlantı noktası<br />\r\n<br />\r\n<strong>Kablosuz</strong>&nbsp;802.11ac çift bant<br />\r\n<br />\r\n<strong>Ethernet</strong>&nbsp;802.3 10/100/1000</p>\r\n\r\n<p>1 adet oyun kolu mevcuttur</p>\r\n\r\n<p>Özel çift bant Xbox Kablosuz radyo</p>\r\n\r\n<p><strong>Ürün ile birlikte hediye oyun gönderilmemektedir</strong></p>\r\n\r\n<p><strong>Ürün 2 yıl Microsoft Türkiye garantisi altındadır</strong></p>\r\n', 'Microsoft', 26020809),
